import{_ as e,o as t,c as i,ad as s}from"./chunks/framework.DdcUsuRQ.js";const u=JSON.parse('{"title":"Contrast pairs","description":"Foreground / background pairs that the engine enforces a minimum ratio on. The accessibility contract of a role schema.","frontmatter":{"title":"Contrast pairs","description":"Foreground / background pairs that the engine enforces a minimum ratio on. The accessibility contract of a role schema.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/role-schema/contrast-pairs"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/role-schema/contrast-pairs"}],["meta",{"property":"og:title","content":"Contrast pairs: iridis"}],["meta",{"property":"og:description","content":"Foreground / background pairs that the engine enforces a minimum ratio on. The accessibility contract of a role schema."}],["meta",{"name":"twitter:title","content":"Contrast pairs: iridis"}],["meta",{"name":"twitter:description","content":"Foreground / background pairs that the engine enforces a minimum ratio on. The accessibility contract of a role schema."}],["meta",{"name":"description","content":"Foreground / background pairs that the engine enforces a minimum ratio on. The accessibility contract of a role schema."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Role Schema\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":4,\\"name\\":\\"Contrast pairs\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema/contrast-pairs\\"}]}"]]},"headers":[],"relativePath":"reference/role-schema/contrast-pairs.md","filePath":"reference/role-schema/contrast-pairs.md","lastUpdated":1779033869000}'),r={name:"reference/role-schema/contrast-pairs.md"};function n(o,a,d,c,l,h){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="contrast-pairs" tabindex="-1">Contrast pairs <a class="header-anchor" href="#contrast-pairs" aria-label="Permalink to &quot;Contrast pairs&quot;">​</a></h1><p>A <code>contrastPairs[]</code> entry declares that two roles, used together as foreground and background, MUST satisfy a minimum contrast ratio. The engine&#39;s <code>enforce:contrast</code> family (WCAG 2.1, APCA, CVD simulation) nudges role colours in OKLCH until every declared pair passes. This is the <strong>accessibility contract</strong> of the schema.</p><h2 id="shape" tabindex="-1">Shape <a class="header-anchor" href="#shape" aria-label="Permalink to &quot;Shape&quot;">​</a></h2><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">interface</span><span style="--shiki-light:var(--iridis-syntax-function);--shiki-dark:var(--iridis-syntax-function);"> ContrastPairInterface</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> {</span></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-variable);--shiki-dark:var(--iridis-syntax-variable);">  foreground</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">:</span><span style="--shiki-light:var(--iridis-syntax-type);--shiki-dark:var(--iridis-syntax-type);"> string</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">;</span><span style="--shiki-light:var(--iridis-syntax-comment);--shiki-dark:var(--iridis-syntax-comment);">          // role name</span></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-variable);--shiki-dark:var(--iridis-syntax-variable);">  background</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">:</span><span style="--shiki-light:var(--iridis-syntax-type);--shiki-dark:var(--iridis-syntax-type);"> string</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">;</span><span style="--shiki-light:var(--iridis-syntax-comment);--shiki-dark:var(--iridis-syntax-comment);">          // role name</span></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-variable);--shiki-dark:var(--iridis-syntax-variable);">  minRatio</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">:</span><span style="--shiki-light:var(--iridis-syntax-type);--shiki-dark:var(--iridis-syntax-type);">   number</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">;</span><span style="--shiki-light:var(--iridis-syntax-comment);--shiki-dark:var(--iridis-syntax-comment);">          // 1..21 for WCAG; 0..107 for APCA Lc</span></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-variable);--shiki-dark:var(--iridis-syntax-variable);">  algorithm</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);">  &#39;wcag21&#39;</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);"> |</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;apca&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">;</span></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">}</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Meaning</th></tr></thead><tbody><tr><td><code>foreground</code></td><td><code>string</code></td><td>Name of the role painted on top.</td></tr><tr><td><code>background</code></td><td><code>string</code></td><td>Name of the role painted underneath.</td></tr><tr><td><code>minRatio</code></td><td><code>number</code></td><td>Minimum contrast the pair must clear. Read against the chosen algorithm&#39;s scale.</td></tr><tr><td><code>algorithm</code></td><td><code>&#39;wcag21&#39; | &#39;apca&#39;</code></td><td>Which contrast formula to use. Defaults to <code>&#39;wcag21&#39;</code>.</td></tr></tbody></table><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p><code>enforce:contrast</code> runs after <code>resolve:roles</code> and <code>expand:family</code>. For each declared pair:</p><ol><li>Compute the actual contrast between the foreground and background using the selected algorithm.</li><li>If the ratio is already ≥ <code>minRatio</code>, do nothing.</li><li>If not, <strong>nudge</strong> the foreground in OKLCH (lift L for dark framing, drop L for light framing) until the ratio passes. Nudge stops when the foreground reaches the L bound of its envelope.</li><li>If the envelope can&#39;t accommodate the required contrast, log an advisory and move on. The role is best-effort; consumers can read <code>state.metadata.wcag.{aa,aaa,apca}.pairs[].pass</code> to see the verdict per pair.</li></ol><p>The verdict surface is the <strong>enforcement output</strong>: pairs that pass cleanly, pairs that pass after nudging, pairs that failed and why. Plugins like the contrast badge on the resolved-roles card read this surface.</p><h2 id="what-it-means" tabindex="-1">What it means <a class="header-anchor" href="#what-it-means" aria-label="Permalink to &quot;What it means&quot;">​</a></h2><p>A contrast pair is a <strong>declarative accessibility constraint</strong>, not a styling hint. Saying <code>{ foreground: &#39;text&#39;, background: &#39;background&#39;, minRatio: 7, algorithm: &#39;wcag21&#39; }</code> is the schema&#39;s commitment that <em>whatever</em> seed the user picks, the engine will produce a <code>text</code> and <code>background</code> such that <code>text</code> on <code>background</code> clears 7:1.</p><p>Common pair sets:</p><ul><li><strong>Floor pairs</strong>: <code>text</code> against every surface (<code>background</code>, <code>bg-soft</code>, <code>surface</code>). Without these, text is unreadable on at least one surface.</li><li><strong>Brand pair</strong>: <code>brand</code> against <code>background</code> at 3:1 (UI element threshold). Guarantees the brand is at least <em>visible</em>, even if not text-readable.</li><li><strong>Status pairs</strong>: <code>success</code>, <code>warning</code>, <code>error</code> against <code>background</code> at 4.5:1. Guarantees status messages remain legible.</li><li><strong>Syntax pairs</strong>: every <code>syntax-*</code> against <code>bg-soft</code> at 4.5:1. Guarantees code stays readable inside code blocks.</li></ul><h2 id="how-to-author" tabindex="-1">How to author <a class="header-anchor" href="#how-to-author" aria-label="Permalink to &quot;How to author&quot;">​</a></h2><ul><li>Declare a pair for <strong>every foreground/background combination that will actually be painted</strong>. Pairs not declared aren&#39;t enforced; the engine can&#39;t read your CSS.</li><li>Use the <strong>algorithm matching your design system</strong>: <ul><li>WCAG 2.1: the legal floor for accessibility audits. <code>4.5:1</code> normal text, <code>3:1</code> large text.</li><li>APCA Lc: the perceptual algorithm targeted by WCAG 3. Lc ≥ 60 for normal text, ≥ 75 for body text, ≥ 90 for dense / chromatic body. Better behaviour on chromatic backgrounds and in dark mode.</li></ul></li><li>Use <code>minRatio: 7</code> for AAA-level pairs (text on body surfaces); <code>4.5</code> for AA-level pairs (text on chromatic accents); <code>3</code> for non-text UI elements (icons, dividers, focus rings).</li><li>Declare pairs in both the dark and light framing variants of the schema. The engine flips L envelopes between framings, so pairs must be enforced separately for each.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../wcag">WCAG 2.1 reference</a>: luminance-ratio algorithm.</li><li><a href="./../apca">APCA reference</a>: perceptual contrast algorithm.</li><li><a href="./../../concepts/contrast">Contrast concept</a>: engine-level overview of the enforcement pipeline.</li><li><a href="./../../concepts/accessibility-calculations">Accessibility calculations</a>: what AA / AAA / APCA mean in practice.</li><li><a href="./../../concepts/role-schemas">Role schemas overview</a>.</li></ul>`,17)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
